pub struct DiskCache {
    cache_dir: PathBuf,
    default_ttl_secs: Option<u64>,
}

impl DiskCache {
    pub fn new(cache_dir: &Path, default_ttl_secs: Option<u64>) -> Result<Self, CacheError> {
        let cache_dir = cache_dir.to_path_buf();

        // Validate path: ensure it's not empty and doesn't contain path traversal
        let canonical_intent = cache_dir
            .to_str()
            .ok_or_else(|| CacheError::InvalidPath("Path contains invalid UTF-8".to_string()))?;

        if canonical_intent.contains("..") {
            return Err(CacheError::InvalidPath(
                "Path traversal detected".to_string(),
            ));
        }

        fs::create_dir_all(&cache_dir)?;

        // Canonicalize after creation to resolve symlinks
        let cache_dir = fs::canonicalize(&cache_dir)?;

        Ok(Self {
            cache_dir,
            default_ttl_secs,
        })
    }

    fn sanitize_key(key: &str) -> Result<String, CacheError> {
        // Only allow alphanumeric, hyphens, underscores, and dots
        let sanitized: String = key
            .chars()
            .map(|c| {
                if c.is_alphanumeric() || c == '-' || c == '_' || c == '.' {
                    c
                } else {
                    '_'
                }
            })
            .collect();

        if sanitized.is_empty() {
            return Err(CacheError::InvalidPath("Empty key".to_string()));
        }

        // Prevent hidden files and path traversal
        if sanitized.starts_with('.') || sanitized.contains("..") {
            return Err(CacheError::InvalidPath(
                "Invalid key format".to_string(),
            ));
        }

        Ok(sanitized)
    }

    fn get_cache_path(&self, key: &str) -> Result<PathBuf, CacheError> {
        let sanitized = Self::sanitize_key(key)?;
        let path = self.cache_dir.join(format!("{}.bin", sanitized));

        // Verify the resolved path is within our cache directory
        let canonical = if path.exists() {
            fs::canonicalize(&path)?
        } else {
            // For new files, canonicalize the parent and append the filename
            let parent = fs::canonicalize(&self.cache_dir)?;
            parent.join(format!("{}.bin", sanitized))
        };

        if !canonical.starts_with(&self.cache_dir) {
            return Err(CacheError::InvalidPath(
                "Path escapes cache directory".to_string(),
            ));
        }

        Ok(canonical)
    }

    pub fn save<T: Serialize>(
        &self,
        key: &str,
        data: &T,
        ttl_secs: Option<u64>,
    ) -> Result<(), CacheError> {
        let entry = CacheEntry {
            data,
            created_at: SystemTime::now(),
            ttl_secs: ttl_secs.or(self.default_ttl_secs),
        };

        let encoded = bincode::serialize(&entry).map_err(|e| {
            CacheError::Serialization(e.to_string())
        })?;

        let path = self.get_cache_path(key)?;

        // Write atomically using a temp file + rename
        let temp_path = path.with_extension("tmp");
        fs::write(&temp_path, &encoded)?;
        fs::rename(&temp_path, &path)?;

        // Set restrictive permissions on Unix
        #[cfg(unix)]
        {
            use std::os::unix::fs::PermissionsExt;
            let perms = fs::Permissions::from_mode(0o600);
            fs::set_permissions(&path, perms)?;
        }

        Ok(())
    }

    pub fn load<T: for<'de> Deserialize<'de>>(&self, key: &str) -> Result<T, CacheError> {
        let path = self.get_cache_path(key)?;

        if !path.exists() {
            return Err(CacheError::NotFound);
        }

        let data = fs::read(&path)?;

        // Limit deserialization size to prevent memory exhaustion (100MB limit)
        const MAX_SIZE: usize = 100 * 1024 * 1024;
        if data.len() > MAX_SIZE {
            return Err(CacheError::Deserialization(
                "Cache file exceeds maximum allowed size".to_string(),
            ));
        }

        let config = bincode::config::DefaultOptions::new()
            .with_limit(MAX_SIZE as u64);

        use bincode::Options;
        let entry: CacheEntry<T> = config.deserialize(&data).map_err(|e| {
            CacheError::Deserialization(e.to_string())
        })?;

        if entry.is_expired() {
            // Clean up expired entry
            let _ = fs::remove_file(&path);
            return Err(CacheError::Expired);
        }

        Ok(entry.data)
    }

    pub fn remove(&self, key: &str) -> Result<(), CacheError> {
        let path = self.get_cache_path(key)?;
        if path.exists() {
            fs::remove_file(&path)?;
        }
        Ok(())
    }

    pub fn clear(&self) -> Result<(), CacheError> {
        for entry in fs::read_dir(&self.cache_dir)? {
            let entry = entry?;
            let path = entry.path();
            if path.is_file()
                && path
                    .extension()
                    .map_or(false, |ext| ext == "bin")
            {
                // Verify path is within cache dir before removing
                let canonical = fs::canonicalize(&path)?;
                if canonical.starts_with(&self.cache_dir) {
                    fs::remove_file(&canonical)?;
                }
            }
        }
        Ok(())
    }

    pub fn exists(&self, key: &str) -> Result<bool, CacheError> {
        let path = self.get_cache_path(key)?;
        Ok(path.exists())
    }

    pub fn cleanup_expired<T: for<'de> Deserialize<'de>>(&self) -> Result<usize, CacheError> {
        let mut removed = 0;
        for entry in fs::read_dir(&self.cache_dir)? {
            let entry = entry?;
            let path = entry.path();
            if path.is_file() && path.extension().map_or(false, |ext| ext == "bin") {
                let canonical = fs::canonicalize(&path)?;
                if !canonical.starts_with(&self.cache_dir) {
                    continue;
                }

                if let Ok(data) = fs::read(&canonical) {
                    let config = bincode::config::DefaultOptions::new()
                        .with_limit(100 * 1024 * 1024);
                    use bincode::Options;
                    if let Ok(entry) = config.deserialize::<CacheEntry<T>>(&data) {
                        if entry.is_expired() {
                            let _ = fs::remove_file(&canonical);
                            removed += 1;
                        }
                    }
                }
            }
        }
        Ok(removed)
    }
}

